// 질문 임베딩 → 벡터 최근접 검색 SQL 생성. 임베딩 실패 시 안내.
const emb = $json.data && $json.data[0] && $json.data[0].embedding;
const topK = Number($('설정 (Config)').first().json.topK) || 20;
if (!Array.isArray(emb) || emb.length !== 1024) {
  return [{ json: { sql: `SELECT '임베딩 서버에 연결하지 못했어요. LM Studio가 켜져 있는지 확인해 주세요.' AS 안내` } }];
}
const vec = '[' + emb.join(',') + ']';
const sql = `SELECT company, title, url, min_career, max_career, tech_stacks, summary, round((1-(embedding <=> '${vec}'::vector))::numeric,3) AS score FROM jobs WHERE status='done' AND embedding IS NOT NULL ORDER BY embedding <=> '${vec}'::vector LIMIT ${topK}`;
return [{ json: { sql } }];

// 결과 포맷 + 마크다운 이스케이프 + Setext 방지 + 파일요청 안내
const rows = $input.all();
const md = (s) => String(s == null ? '' : s).replace(/[\\`*_~#|>\[\]]/g, '\\$&').replace(/\r?\n/g, ' ').trim();
const val = (v) => Array.isArray(v) ? v.map(md).join(', ') : (v === '' || v == null ? '(미분류)' : md(v));
let text;
if (rows.length === 0) { text = '🔎 결과가 없어요.'; }
else {
  const first = rows[0].json; const keys = Object.keys(first);
  if ('sql' in first || 'error' in first) text = '⚠️ 쿼리를 실행하지 못했어요. 질문을 조금 다르게 표현해 주세요.';
  else if (keys.length === 1 && keys[0] === '안내') text = '⚠️ ' + md(first['안내']);
  else if ('title' in first) {
    text = `🔎 **${rows.length}건**\n\n`;
    for (const r of rows) {
      const m = r.json;
      const career = [m.min_career, m.max_career].filter(v => v != null).join('~') || '무관';
      const st = Array.isArray(m.tech_stacks) ? m.tech_stacks.filter(Boolean).map(md).join(', ') : '';
      text += `**${md(m.company)} — ${md(m.title)}**  ·  경력 ${career}${m.score!=null?`  ·  관련도 ${Math.round(m.score*100)}%`:''}\n`;
      if (st) text += `${st}\n`;
      if (m.url) text += `${m.url}\n`;
      text += '\n';
    }
  } else if (keys.length === 1) text = `🔎 결과: **${val(first[keys[0]])}**`;
  else {
    const numKey = keys.find(k => rows.every(r => typeof r.json[k] === 'number' || /^-?\d+(\.\d+)?$/.test(String(r.json[k]))));
    const labelKey = keys.find(k => k !== numKey);
    if (keys.length === 2 && numKey && labelKey) { text = `📊 **${rows.length}개**\n\n`; rows.forEach((r,i)=>{ text += `${i+1}. **${val(r.json[labelKey])}** — ${r.json[numKey]}\n`; }); }
    else { text = `🔎 **${rows.length}행**\n\n| ${keys.map(md).join(' | ')} |\n| ${keys.map(()=>'---').join(' | ')} |\n`; for (const r of rows) text += '| ' + keys.map(k=>val(r.json[k])).join(' | ') + ' |\n'; }
  }
}
// 파일 요청이면 안내 추가
if (!text.startsWith('⚠️') && !text.startsWith('🔎 결과가 없어요')) text += '\n📎 이 결과를 RTF/DOCX 파일로 저장하고 디스코드로 보냈어요.';
return [{ json: { output: text, text } }];

// 질문에 파일/문서/rtf 요청이 있을 때만 RTF 파일 생성. 아니면 [] (파일 안 만듦).
const q = ($('채팅 트리거').first().json.chatInput) || '검색';
const rows = $input.all();
if (rows.length === 0) return [];
const f0 = rows[0].json;
if ('안내' in f0 || 'sql' in f0 || 'error' in f0) return [];  // 검증차단/실패는 파일 안 만듦

// RTF 이스케이프: \ { } 및 비ASCII(한글 등) 유니코드 이스케이프(\uNNNN?)
const esc = (s) => {
  let out = '';
  for (const ch of String(s == null ? '' : s)) {
    const code = ch.codePointAt(0);
    if (ch === '\\') out += '\\\\';
    else if (ch === '{') out += '\\{';
    else if (ch === '}') out += '\\}';
    else if (code > 127) { const c = code > 32767 ? code - 65536 : code; out += '\\u' + c + '?'; }
    else out += ch;
  }
  return out;
};

let bodyRtf = '';
const isJobs = 'title' in rows[0].json;
if (isJobs) {
  bodyRtf += '{\\fs36\\b ' + esc('채용 공고 검색 결과 (' + rows.length + '건)') + '}\\par\\par ';
  for (const r of rows) {
    const m = r.json;
    const career = [m.min_career, m.max_career].filter(v => v != null).join('~') || '무관';
    const st = Array.isArray(m.tech_stacks) ? m.tech_stacks.filter(Boolean).join(', ') : '';
    bodyRtf += '{\\b ' + esc((m.company||'') + ' — ' + (m.title||'')) + '}  (' + esc('경력 ' + career) + ')\\par ';
    if (st) bodyRtf += esc(st) + '\\par ';
    if (m.url) bodyRtf += esc(m.url) + '\\par ';
    bodyRtf += '\\par ';
  }
} else {
  const keys = Object.keys(rows[0].json);
  bodyRtf += '{\\fs36\\b ' + esc('검색 결과 (' + rows.length + '행)') + '}\\par\\par ';
  bodyRtf += '{\\b ' + esc(keys.join(' | ')) + '}\\par ';
  for (const r of rows) bodyRtf += esc(keys.map(k => Array.isArray(r.json[k]) ? r.json[k].join(', ') : r.json[k]).join(' | ')) + '\\par ';
}
const rtf = '{\\rtf1\\ansi\\ansicpg949\\deff0{\\fonttbl{\\f0\\fnil Malgun Gothic;}}\\f0\\fs24 ' + bodyRtf + '}';

// 파일명: 정제 키워드_건수_시각(KST). 원본 질문에서 요청어/조사 제거해 핵심어만 남김.
const FILLER = /(관련된|관련|직무를|직무|직군|포지션|공고를|공고|채용|일자리|자리|찾아주세요|찾아줘|찾아|찾고|찾는|보여주세요|보여줘|알려주세요|알려줘|검색해줘|검색|해주세요|해줘|주세요|싶어요|싶어|싶은|좀|목록|리스트|전체|전부|모두|문서로|문서|파일로|파일|rtf로|rtf|docx로|docx|만들어줘|만들어|줄래|해줄래|주라|줘)/g;
const JOSA = /(으로|로|를|을|은|는|이|가|의|에서|에게|한테|와|과|도|만|랑|이랑|에)$/;
let kw = q.replace(/[\\/:*?"<>|\n\r]+/g, ' ').replace(FILLER, ' ').replace(/\s+/g, ' ').trim();
kw = kw.split(' ').map(t => t.replace(JOSA, '')).filter(Boolean).join('_').replace(/[^\w가-힣_]/g, '').replace(/_+/g, '_').replace(/^_+|_+$/g, '').slice(0, 24);
if (!kw) kw = '검색결과';
const d = new Date();
const pad = (x) => String(x).padStart(2, '0');
const ts = `${pad(d.getMonth()+1)}${pad(d.getDate())}-${pad(d.getHours())}${pad(d.getMinutes())}`;
const filename = `${kw}_${rows.length}건_${ts}.rtf`;
const binary = await this.helpers.prepareBinaryData(Buffer.from(rtf, 'utf-8'), filename, 'application/rtf');
return [{ json: { filename }, binary: { data: binary } }];
